promptTemplate.template:
Write a Facebook/Instagram caption for {brandName}.
Offer / topic: {offerOrTopic}
Tone: {tone: e.g. friendly, professional, playful}
Call to action: {cta: e.g. Book now via DM, Visit our store, Call {phone}}
Target audience: {audience}
Language: {language, default: English}
Constraints: single caption, plain text, hook on line 1, 3-6 relevant hashtags on the last line.
